import { AsyncPipe } from '@angular/common';
import { Component, computed, inject, signal } from '@angular/core';
import { AXFormatPipe, AXFormatService } from '@acorex/core/format';

@Component({
  selector: 'app-format-basic-usage',
  imports: [AsyncPipe, AXFormatPipe],
  template: `
    <p>Pipe: {{ amount() | format: 'number': numberOptions | async }}</p>
    <p>Service: {{ formattedAmount() }}</p>
    <p>{{ greeting() }}</p>
  `,
})
export class FormatBasicUsageComponent {
  private formatService = inject(AXFormatService);

  protected amount = signal(1234567.89);
  protected numberOptions = { locale: 'en-US', decimalPlaces: 2 };

  protected formattedAmount = computed(() =>
    this.formatService.format(this.amount(), 'number', this.numberOptions),
  );

  protected greeting = computed(() =>
    this.formatService
      .format('Hello {{ user.name }}!')
      .to('string', { user: { name: 'AcoreX' } }),
  );
}

import { Component, inject } from '@angular/core';
import { AXFormatService } from '@acorex/core/format';

@Component({
  selector: 'app-calendar-nav',
  template: `<h2>{{ navText }}</h2>`,
})
export class CalendarNavComponent {
  private formatService = inject(AXFormatService);

  navText = '';

  setRange(start: Date, end: Date) {
    const d1 = this.formatService.format(start, 'datetime', { format: 'MMM yyyy' });
    const d2 = this.formatService.format(end, 'datetime', { format: 'MMM yyyy' });
    this.navText = `${d1} - ${d2}`;
  }
}

