import { AXFormatService } from '@acorex/core/format';
import { inject } from '@angular/core';

const formatService = inject(AXFormatService);

// Locale-aware (uses Intl.NumberFormat for separators)
formatService.format(1234567.89, 'number', { locale: 'en-US', decimalPlaces: 2 });
// → '1,234,567.89'

formatService.format(1234567.89, 'number', { locale: 'de-DE', decimalPlaces: 2 });
// → '1.234.567,89'

// Zero-padded integer part
formatService.format(42, 'number', { zeroPadLength: 6 });
// → '000042'

import { AXFormatService } from '@acorex/core/format';
import { inject } from '@angular/core';

const formatService = inject(AXFormatService);

// Interpolate {{ path }} placeholders using lodash get()
formatService.format('Hello {{ user.name }}!', {
  user: { name: 'Ali' },
});
// → 'Hello Ali!'

// If options contains a key matching the entire value, that value is returned
formatService.format('greeting.key', {
  'greeting.key': 'Welcome back',
});
// → 'Welcome back'

