import { AXFormatOptions, AXFormatter } from '@acorex/core/format';
import { Injectable } from '@angular/core';

export interface AXPercentFormatterOptions extends AXFormatOptions {
  decimalPlaces?: number;
}

// Extend the type map for fluent API autocomplete
declare module '@acorex/core/format' {
  interface AXFormatOptionsMap {
    percent: AXPercentFormatterOptions;
  }
}

@Injectable()
export class AXPercentFormatter implements AXFormatter {
  get name() {
    return 'percent';
  }

  format(value: unknown, options?: AXPercentFormatterOptions): string {
    const num = Number(value);
    if (Number.isNaN(num)) return '—';
    const digits = options?.decimalPlaces ?? 1;
    return `${(num * 100).toFixed(digits)}%`;
  }
}

